import React from 'react';
import Modal from 'react-modal';
import { Link } from "react-router-dom";

Modal.setAppElement('#root');

const AddToCartModal = ({ isOpen, onRequestClose }) => {

    const continueShopping = () => {
        onRequestClose();
    };

    return (
        <Modal isOpen={isOpen} onRequestClose={onRequestClose} contentLabel="Product has been added to cart">
            <div className="p-4 text-center">
                <h2 className="text-xl font-semibold">Product has been added to cart</h2>
                <div className="mt-4">
                    <Link to='/cart' className="bg-blue-500 text-white py-2 px-4 rounded mr-2">
                        Go to cart
                    </Link>
                    <button onClick={continueShopping} className="bg-gray-500 text-white py-2 px-4 rounded">
                        Continue shopping
                    </button>
                </div>
            </div>
        </Modal>
    );

}

export default AddToCartModal;
